import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.jWxB9oXr.js";const m=JSON.parse('{"title":"About Silvery","description":"About Silvery — a React TUI framework for modern terminal applications. Origin story, technical approach, and ecosystem.","frontmatter":{"title":"About Silvery","description":"About Silvery — a React TUI framework for modern terminal applications. Origin story, technical approach, and ecosystem.","head":[["meta",{"property":"og:title","content":"About Silvery"}],["meta",{"property":"og:description","content":"About Silvery — a React TUI framework for modern terminal applications. Origin story, technical approach, and ecosystem."}],["meta",{"property":"og:url","content":"https://silvery.dev/about.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/about.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"About Silvery\\",\\"item\\":\\"https://silvery.dev/about\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"About Silvery\\",\\"description\\":\\"About Silvery — a React TUI framework for modern terminal applications. Origin story, technical approach, and ecosystem.\\",\\"url\\":\\"https://silvery.dev/about.html\\",\\"dateModified\\":\\"2026-04-10T20:29:54.000Z\\",\\"datePublished\\":\\"2026-04-10T20:29:54.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1775852994000}'),s={name:"about.md"};function o(n,e,l,d,h,p){return a(),r("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /about.md for this page in Markdown format</div><h1 id="about-silvery" tabindex="-1">About Silvery <a class="header-anchor" href="#about-silvery" aria-label="Permalink to &quot;About Silvery&quot;">​</a></h1><p>Polished terminal apps in React. 45+ components, layout-first rendering, broad terminal protocol support. Pure TypeScript, no <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>. Runs on Bun and Node.js (23.6+).</p><h2 id="how-it-started" tabindex="-1">How It Started <a class="header-anchor" href="#how-it-started" aria-label="Permalink to &quot;How It Started&quot;">​</a></h2><p>I was building a terminal application — a multi-pane workspace with a kanban-style board, thousands of nodes, and keyboard-driven navigation. I started with <a href="https://github.com/vadimdemedes/ink" target="_blank" rel="noreferrer">Ink</a>, which is a great project and the right choice for most terminal apps.</p><p>I ran into two problems I couldn&#39;t work around:</p><p><strong>Components can&#39;t know their size during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>.</strong> In <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>, React renders first, then <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> calculates layout. So when your component runs, it doesn&#39;t know how wide its container is. <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 added <code>useBoxMetrics()</code>, which provides dimensions after the first layout via <code>useEffect</code> — but the first <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> still sees <code>{width: 0, height: 0}</code>, and nested responsive components each need their own measure→rerender cycle.</p><p><strong>Every update re-reconciles the entire tree.</strong> When a user moves a cursor in a 1000-node tree, <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> re-runs React <span class="glossary-hint" data-tooltip="The process of comparing old and new React trees to determine what changed">reconciliation</span> and <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> layout for the full tree. <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 added line-level incremental output, but the React and layout passes still walk everything. For my application, that took about 20 milliseconds per keypress — noticeable at 60fps.</p><p>I needed layout to <a href="/api/render" class="hover-link" data-tooltip="Sugar over pipe() with sensible defaults — the simplest way to start an app">run</a> <em>before</em> rendering (so components could access their dimensions), and per-node dirty tracking (so only changed nodes would re-<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>). That required a different rendering pipeline, which meant building a new renderer.</p><p>What started as fixing two <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> limitations grew into something much broader — a complete terminal UI framework with its own layout engine, 45+ components, theming, terminal protocol negotiation, state machines, and testing infrastructure. The renderer and <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> were the starting point, but they&#39;re a small part of what Silvery is today.</p><h2 id="how-it-grew" tabindex="-1">How It Grew <a class="header-anchor" href="#how-it-grew" aria-label="Permalink to &quot;How It Grew&quot;">​</a></h2><p>The renderer needed a layout engine. I started with a two-phase layout based on <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>, but questioned whether the <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> tax was worth paying — the async initialization, the binary blob, the separate memory heap. So I built <a href="https://beorn.codes/flexily" target="_blank" rel="noreferrer">Flexily</a>, a pure-TypeScript flexbox engine that follows the W3C spec. It turned out to be 2.5× faster than <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>, with zero native dependencies.</p><p>Testing the renderer meant testing against real terminals. I missed Playwright — the confidence you get from running your app in a real browser and asserting on what the user sees. So I built <a href="https://termless.dev" target="_blank" rel="noreferrer">Termless</a>, which runs your terminal app through real parser backends (xterm.js, vt100, Ghostty, Kitty, Alacritty, and more) in-process. Playwright-style testing for the terminal.</p><p>But there was a surprising lack of information about what terminals actually support. Which ones handle <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Extended keyboard protocol with 5 flags — disambiguate, event types, alternate keys, all keys, associated text. Enables modifier detection and key release events.">Kitty keyboard</a>? <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a> clipboard? Sixel graphics? The answers were scattered across source code, GitHub issues, and trial-and-error. So I built <a href="https://terminfo.dev" target="_blank" rel="noreferrer">terminfo.dev</a> — an empirical compatibility database covering 161 features across 19 terminals, all probed via <a href="https://termless.dev" class="hover-link" data-tooltip="Headless terminal testing framework — like Playwright, but for terminal apps" target="_blank" rel="noopener">Termless</a>.</p><p>Inside Silvery itself, the same pattern repeated. The framework needed a theme system that auto-detects terminal colors and adjusts for contrast — that became <a href="https://silvery.dev/themes" target="_blank" rel="noreferrer">@silvery/theme</a> with 38 palettes and semantic tokens. It needed built-in testing utilities — that became <a href="https://silvery.dev/examples/testing" target="_blank" rel="noreferrer">@silvery/test</a> with Playwright-style locators and <code>press()</code> simulation. CLI apps needed beautiful help text — that became <a href="https://silvery.dev/reference/commander" target="_blank" rel="noreferrer">@silvery/commander</a>, which renders its help through Silvery itself.</p><p>It&#39;s a little addictive, owning the entire pipeline. Each piece you build reveals the next opportunity. And there are a lot of opportunities that have come — and will come — out of having every layer work together.</p><p>Along the way, three principles emerged. Take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p><strong>Layout first, then <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>.</strong> Silvery inverts the pipeline: <a href="https://beorn.codes/flexily" target="_blank" rel="noreferrer">Flexily</a> (a <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible layout engine) calculates positions and sizes, then React renders components with their actual content box available via <code>useBoxRect()</code>:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IssueCard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">issue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">issue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Issue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useBoxRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> width </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 32</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">FullCard</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> issue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{issue} /&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CompactCard</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> issue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{issue} /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Because width is known during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>, this works on the first paint — no prop drilling, no measurement pass, no <code>width: 0</code> flash. The same mechanism makes <code>overflow=&quot;scroll&quot;</code> and automatic text truncation possible.</p><p><strong>Incremental rendering.</strong> Each node tracks dirty state independently. A typical interactive update — cursor move in a 1000-node tree — takes 169 microseconds. The <a href="/guide/silvery-vs-ink.html#performance">benchmark comparison</a> has the full numbers and methodology.</p><p><strong>Pure TypeScript.</strong> The entire stack, including the layout engine, is TypeScript with no native dependencies. No <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> heap to manage, no platform-specific binaries, no C++ build step.</p><p><strong><a href="/guide/the-silvery-way.html">The Silvery Way</a>.</strong> Ten design principles for building terminal apps with Silvery. The short version: use the high-level components (<a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>, <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>), use semantic theme tokens (<code>$primary</code>, <code>$muted</code>), and let the framework handle focus management, key bindings, and scrolling.</p><h2 id="ecosystem" tabindex="-1">Ecosystem <a class="header-anchor" href="#ecosystem" aria-label="Permalink to &quot;Ecosystem&quot;">​</a></h2><p>All MIT-licensed, all part of the same development effort.</p><h3 id="packages" tabindex="-1">Packages <a class="header-anchor" href="#packages" aria-label="Permalink to &quot;Packages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Package</th><th>Description</th></tr></thead><tbody><tr><td><code>silvery</code></td><td>Components, hooks, renderer — the one package you need</td></tr><tr><td><code>@silvery/ink</code> / <code>@silvery/chalk</code></td><td><a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> compatibility — 99% of <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 tests, 100% of Chalk tests</td></tr><tr><td><code>@silvery/test</code></td><td>Playwright-style testing — locators, <code>press()</code>, buffer assertions</td></tr><tr><td><code>@silvery/create</code></td><td>Composable app builder — <code>pipe()</code> providers <em>(under active development)</em></td></tr><tr><td><code>@silvery/theme</code></td><td>38 palettes, semantic tokens (<code>$primary</code>, <code>$muted</code>), auto-detect</td></tr><tr><td><code>@silvery/commander</code></td><td><strong>Beautiful CLIs for free</strong> — help renders through Silvery itself</td></tr><tr><td><code>@silvery/headless</code></td><td>Pure state machines — portable, embeddable, no React</td></tr><tr><td><code>@silvery/ansi</code></td><td>Terminal primitives — styling, SGR, truecolor, detection</td></tr></tbody></table><h3 id="standalone-projects" tabindex="-1">Standalone projects <a class="header-anchor" href="#standalone-projects" aria-label="Permalink to &quot;Standalone projects&quot;">​</a></h3><p>Each stands on its own — Silvery builds on them, but they work independently:</p><ul><li><strong><a href="https://beorn.codes/flexily" target="_blank" rel="noreferrer">Flexily</a></strong> — Pure-TypeScript flexbox layout engine, <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible, W3C spec. 2.5× faster than <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>, zero native dependencies.</li><li><strong><a href="https://termless.dev" target="_blank" rel="noreferrer">Termless</a></strong> — Headless terminal testing against 10+ real parser backends. Like Playwright for terminal apps.</li><li><strong><a href="https://terminfo.dev" target="_blank" rel="noreferrer">terminfo.dev</a></strong> — Terminal feature compatibility database. 161 features × 19 terminals, empirically probed via <a href="https://termless.dev" class="hover-link" data-tooltip="Headless terminal testing framework — like Playwright, but for terminal apps" target="_blank" rel="noopener">Termless</a>.</li><li><strong><a href="https://beorn.codes/loggily" target="_blank" rel="noreferrer">Loggily</a></strong> — Structured logging + span tracing + metrics in one library. Zero dependencies.</li></ul><h2 id="numbers" tabindex="-1">Numbers <a class="header-anchor" href="#numbers" aria-label="Permalink to &quot;Numbers&quot;">​</a></h2><ul><li>45+ components — <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>, <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a>, <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>, <a href="/api/command-palette" class="hover-link" data-tooltip="VS Code-style fuzzy command palette with keyboard navigation">CommandPalette</a>, <a href="/components/TreeView" class="hover-link" data-tooltip="Expandable/collapsible tree navigation component">TreeView</a>, <a href="/api/table" class="hover-link" data-tooltip="Column-aligned table component with headers and auto-sizing">Table</a>, <a href="/components/Form" class="hover-link" data-tooltip="Vertical form layout with labeled fields, validation, and submit handling">Form</a>, and more</li><li>23 color palettes with semantic tokens and WCAG-aware contrast</li><li><a href="/guide/silvery-vs-ink.html#compatibility">~99% of Ink 7.0&#39;s test suite (918/931)</a> passes via the compatibility layer</li><li>Runs on Bun and Node.js 23.6+</li></ul><p>Silvery is a good fit for interactive, keyboard-heavy terminal apps with large or responsive UIs. For simpler CLIs, output-only tools, or apps that rebuild the full screen on every update, <a href="https://github.com/vadimdemedes/ink" target="_blank" rel="noreferrer">Ink</a> is a solid choice with a bigger ecosystem. If you don&#39;t want React or TypeScript, frameworks in Go, Python, and Rust may be a better fit.</p><h2 id="inspirations" tabindex="-1">Inspirations <a class="header-anchor" href="#inspirations" aria-label="Permalink to &quot;Inspirations&quot;">​</a></h2><p>Silvery stands on the shoulders of many great projects:</p><ul><li><strong><a href="https://github.com/vadimdemedes/ink" target="_blank" rel="noreferrer">Ink</a></strong> — defined React for terminals. Silvery&#39;s API is intentionally <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>-compatible.</li><li><strong><a href="https://github.com/chalk/chalk" target="_blank" rel="noreferrer">Chalk</a></strong> — terminal string styling. Silvery includes a full Chalk compat layer (100% test pass).</li><li><strong><a href="https://ratatui.rs/" target="_blank" rel="noreferrer">Ratatui</a></strong> — the cell-level buffer model and immediate-mode rendering approach.</li><li><strong><a href="https://www.slatejs.org/" target="_blank" rel="noreferrer">SlateJS</a></strong> — plugin composition via <code>pipe()</code>, operations-as-data, middleware transforms.</li><li><strong><a href="https://guide.elm-lang.org/architecture/" target="_blank" rel="noreferrer">The Elm Architecture</a> / <a href="https://github.com/charmbracelet/bubbletea" target="_blank" rel="noreferrer">BubbleTea</a></strong> — <span class="glossary-hint" data-tooltip="The Elm Architecture — (action, state) → [state, effects] pattern for structured interactive state">TEA</span> state machines: <code>(action, state) → [state, effects]</code>.</li><li><strong>CSS/Web platform</strong> — flexbox layout, container queries (<code>useBoxRect</code>), DOM-style events, focus scopes, <code>overflow: scroll</code>, <code>position: sticky</code>.</li><li><strong><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VS Code</a></strong> — command palette, keybinding system with when-predicates.</li><li><strong><a href="https://playwright.dev/" target="_blank" rel="noreferrer">Playwright</a></strong> — locator-based testing API (<code>getByText</code>, <code>press()</code>).</li><li><strong><a href="https://prosemirror.net/" target="_blank" rel="noreferrer">ProseMirror</a></strong> — selection model and state machine approach to editing.</li><li><strong><a href="https://chenglou.me/pretext/" target="_blank" rel="noreferrer">Pretext</a></strong> — text layout beyond CSS. Inspired Silvery&#39;s <a href="/guide/layouts.html#text-layout">text layout</a> algorithms.</li><li><strong><a href="https://github.com/chjj/blessed" target="_blank" rel="noreferrer">Blessed</a></strong> — proved rich terminal UIs are possible in JavaScript.</li><li><strong><a href="https://textual.textualize.io/" target="_blank" rel="noreferrer">Textual</a></strong> — CSS-like theming and widget library for terminals.</li></ul><p>See also: <a href="/guide/silvery-vs-ink.html">Silvery vs Ink</a>, <a href="/guide/silvery-vs-bubbletea.html">Silvery vs BubbleTea</a>, <a href="/guide/silvery-vs-textual.html">Silvery vs Textual</a>, <a href="/guide/silvery-vs-blessed.html">Silvery vs Blessed</a>.</p><h2 id="author" tabindex="-1">Author <a class="header-anchor" href="#author" aria-label="Permalink to &quot;Author&quot;">​</a></h2><p><a href="https://beorn.codes" target="_blank" rel="noreferrer">Bjørn Stabell</a> — entrepreneur and technologist based in the SF Bay Area. Building companies and developer tools since 2000.</p><p>Currently building AI products for knowledge work, and open-source infrastructure for the terminal ecosystem: <a href="https://silvery.dev" target="_blank" rel="noreferrer">Silvery</a>, <a href="https://terminfo.dev" target="_blank" rel="noreferrer">terminfo.dev</a>, <a href="https://termless.dev" target="_blank" rel="noreferrer">Termless</a>, <a href="https://beorn.codes/flexily" target="_blank" rel="noreferrer">Flexily</a>, and <a href="https://beorn.codes/loggily" target="_blank" rel="noreferrer">Loggily</a>.</p><p><a href="https://beorn.codes" target="_blank" rel="noreferrer">beorn.codes</a> · <a href="https://github.com/beorn" target="_blank" rel="noreferrer">GitHub</a> · <a href="https://linkedin.com/in/beorn" target="_blank" rel="noreferrer">LinkedIn</a> · <a href="https://x.com/beorn" target="_blank" rel="noreferrer">X</a></p>`,42)])])}const u=t(s,[["render",o]]);export{m as __pageData,u as default};
